// node_conv_234 -- tiled-streaming 3x3 conv2d.
//   IC=128, OC=128, IH=IW=28, stride=1, padding=1, MP=4.
//   channel_tile=32 -> IN_BEATS=4, OUT_BEATS=4 per pixel.
//
// Split-architecture (coord_scheduler + line_buf_window + conv_datapath)
// wrapped with a 4-beat input aggregator + 4-beat output splitter.

module node_conv_234 (
    input  wire                       clk,
    input  wire                       rst_n,
    input  wire                       valid_in,
    output wire                       ready_in,
    input  wire [255:0]               data_in,
    output wire                       valid_out,
    output wire [255:0]               data_out
);
    localparam integer IC             = 128;
    localparam integer OC             = 128;
    localparam integer IH             = 28;
    localparam integer IW             = 28;
    localparam integer OH             = 28;
    localparam integer OW             = 28;
    localparam integer KH             = 3;
    localparam integer KW             = 3;
    localparam integer SH             = 1;
    localparam integer SW             = 1;
    localparam integer PH             = 1;
    localparam integer PW             = 1;
    localparam integer K_TOTAL        = IC * KH * KW;
    localparam integer MP             = 4;

    localparam integer SCALE_MULT     = 29481;
    localparam integer SCALE_SHIFT    = 23;

    localparam integer CHANNEL_TILE   = 32;
    localparam integer TILE_BITS      = CHANNEL_TILE * 8;
    localparam integer IN_PIXEL_BITS  = IC * 8;
    localparam integer OUT_PIXEL_BITS = OC * 8;

    wire                                sched_needs_real_input;
    wire                                sched_ready_in;
    wire                                sched_output_fires;
    wire                                sched_advance;
    wire [$clog2(IH + PH + 1)-1:0]      sched_in_row;
    wire [$clog2(IW + PW + 1)-1:0]      sched_in_col;
    wire [$clog2(OH * OW + 1)-1:0]      sched_outputs_emitted;
    wire                                sched_out_frame_done;

    wire [KH*KW*IC*8-1:0]               window_flat;
    wire                                mac_busy;
    wire                                lib_valid_out_w;
    wire [OUT_PIXEL_BITS-1:0]           lib_data_out_w;

    localparam ST_ARM  = 2'd0;
    localparam ST_RUN  = 2'd1;
    localparam ST_WAIT = 2'd2;

    reg [1:0] frame_state;
    reg       start_pulse;

    reg  [1:0]                          in_beat_idx;
    reg  [TILE_BITS-1:0]                pixel_buf_r0;
    reg  [TILE_BITS-1:0]                pixel_buf_r1;
    reg  [TILE_BITS-1:0]                pixel_buf_r2;

    wire                                last_in_beat = (in_beat_idx == 2'd3);

    // [INVARIANT:READY_IN_GATING]
    assign ready_in = last_in_beat ? sched_ready_in : 1'b1;

    wire                                lib_valid_in_w = valid_in && last_in_beat && sched_ready_in;
    wire [IN_PIXEL_BITS-1:0]            lib_data_in_w  = {data_in, pixel_buf_r2, pixel_buf_r1, pixel_buf_r0};

    reg                                 out_streaming_r;
    reg  [1:0]                          out_beat_idx;
    reg  [TILE_BITS-1:0]                out_buf_r1;
    reg  [TILE_BITS-1:0]                out_buf_r2;
    reg  [TILE_BITS-1:0]                out_buf_r3;

    // [INVARIANT:VALID_OUT_LATENCY]
    assign valid_out = lib_valid_out_w || out_streaming_r;
    assign data_out  = (out_streaming_r && out_beat_idx == 2'd1) ? out_buf_r1 :
                       (out_streaming_r && out_beat_idx == 2'd2) ? out_buf_r2 :
                       (out_streaming_r && out_beat_idx == 2'd3) ? out_buf_r3 :
                       lib_data_out_w[TILE_BITS-1:0];

    always @(posedge clk or negedge rst_n) begin
        if (!rst_n) begin
            frame_state         <= ST_ARM;
            start_pulse         <= 1'b0;
            in_beat_idx         <= 2'd0;
            pixel_buf_r0        <= {TILE_BITS{1'b0}};
            pixel_buf_r1        <= {TILE_BITS{1'b0}};
            pixel_buf_r2        <= {TILE_BITS{1'b0}};
            out_streaming_r     <= 1'b0;
            out_beat_idx        <= 2'd0;
            out_buf_r1          <= {TILE_BITS{1'b0}};
            out_buf_r2          <= {TILE_BITS{1'b0}};
            out_buf_r3          <= {TILE_BITS{1'b0}};
        end else begin
            start_pulse <= 1'b0;

            case (frame_state)
                ST_ARM: begin
                    start_pulse <= 1'b1;
                    frame_state <= ST_RUN;
                end
                ST_RUN: begin
                    if (sched_out_frame_done) frame_state <= ST_WAIT;
                end
                ST_WAIT: begin
                    if (!mac_busy && !out_streaming_r && !lib_valid_out_w)
                        frame_state <= ST_ARM;
                end
                default: frame_state <= ST_ARM;
            endcase

            if (valid_in && ready_in) begin
                case (in_beat_idx)
                    2'd0: pixel_buf_r0 <= data_in;
                    2'd1: pixel_buf_r1 <= data_in;
                    2'd2: pixel_buf_r2 <= data_in;
                    default: ;
                endcase
                if (last_in_beat) in_beat_idx <= 2'd0;
                else              in_beat_idx <= in_beat_idx + 2'd1;
            end

            if (lib_valid_out_w) begin
                out_buf_r1      <= lib_data_out_w[2*TILE_BITS-1:1*TILE_BITS];
                out_buf_r2      <= lib_data_out_w[3*TILE_BITS-1:2*TILE_BITS];
                out_buf_r3      <= lib_data_out_w[4*TILE_BITS-1:3*TILE_BITS];
                out_streaming_r <= 1'b1;
                out_beat_idx    <= 2'd1;
            end else if (out_streaming_r) begin
                if (out_beat_idx == 2'd3) begin
                    out_streaming_r <= 1'b0;
                    out_beat_idx    <= 2'd0;
                end else begin
                    out_beat_idx <= out_beat_idx + 2'd1;
                end
            end
        end
    end

    wire stall_in = mac_busy;

    coord_scheduler #(
        .IH(IH), .IW(IW), .OH(OH), .OW(OW),
        .KH(KH), .KW(KW), .SH(SH), .SW(SW),
        .PH(PH), .PW(PW)
    ) scheduler (
        .clk(clk), .rst_n(rst_n),
        .start(start_pulse),
        .stall_in(stall_in),
        .valid_in(lib_valid_in_w),
        .ready_in(sched_ready_in),
        .needs_real_input(sched_needs_real_input),
        .in_row(sched_in_row),
        .in_col(sched_in_col),
        .output_fires(sched_output_fires),
        .advance(sched_advance),
        .in_frame_done(),
        .out_frame_done(sched_out_frame_done),
        .outputs_emitted(sched_outputs_emitted)
    );

    line_buf_window #(
        .IC(IC), .IW(IW), .IH(IH),
        .KH(KH), .KW(KW), .PW(PW), .PH(PH)
    ) lbw (
        .clk(clk), .rst_n(rst_n),
        .frame_start(start_pulse),
        .sched_in_row(sched_in_row),
        .sched_in_col(sched_in_col),
        .sched_needs_real_input(sched_needs_real_input),
        .sched_advance(sched_advance),
        .sched_output_fires(sched_output_fires),
        .valid_in(lib_valid_in_w),
        .data_in(lib_data_in_w),
        .window_flat(window_flat)
    );

    conv_datapath #(
        .IC(IC), .OC(OC), .KH(KH), .KW(KW),
        .K_TOTAL(K_TOTAL), .MP(MP),
        .SCALE_MULT(SCALE_MULT), .SCALE_SHIFT(SCALE_SHIFT),
        .WEIGHTS_PATH("C:/Users/User/Desktop/RTL_LLM_CLAUDE/nn2rtl-repo/output/weights/node_conv_234_weights.hex"),
        .BIAS_PATH("C:/Users/User/Desktop/RTL_LLM_CLAUDE/nn2rtl-repo/output/weights/node_conv_234_bias.hex")
    ) dp (
        .clk(clk), .rst_n(rst_n),
        .window_flat(window_flat),
        .start_mac(sched_output_fires),
        .valid_out(lib_valid_out_w),
        .data_out(lib_data_out_w),
        .mac_busy(mac_busy)
    );

endmodule
